// Monta resposta e payload de log em um único nó
// Evita referências a .item de nós anteriores que quebraram o pairedItem
const items = $input.all();
const ef = $('Edit Fields').first().json;

const linhasGravadas = items.length;

return [{
  json: {
    // resposta ao frontend
    resposta: {
      sucesso: true,
      empresa: ef.empresa,
      periodo: ef.periodo,
      linhas_gravadas: linhasGravadas,
      processado_em: new Date().toISOString()
    },
    // payload do log
    log: {
      cliente_id:      ef.cliente_id     || null,
      empresa_id:      ef.empresa_id     || null,
      emp_integra_id:  ef.empresa,
      calc_periodo:    ef.periodo,
      user_calc:       ef.user_id        || null,
      ip_disparo:      ef.ip_disp        || null,
      origem_disparo:  ef.origem_disparo || null,
      linhas_gravadas: linhasGravadas,
      status_calc:     'sucesso'
    }
  }
}];

const items = $input.all();

items.sort((a, b) => {
  if (a.json.dre_linha_nivel !== b.json.dre_linha_nivel) {
    return a.json.dre_linha_nivel - b.json.dre_linha_nivel;
  }
  return a.json.dre_linha_seq - b.json.dre_linha_seq;
});

return items;

// ===== NODE 1: BASE (CONTA + CONSTANTE) =====
const items = $input.all();
const meses = [
  'conta_janeiro', 'conta_fevereiro', 'conta_marco', 'conta_abril',
  'conta_maio', 'conta_junho', 'conta_julho', 'conta_agosto',
  'conta_setembro', 'conta_outubro', 'conta_novembro', 'conta_dezembro'
];

let periodoLimite = null;
items.forEach(item => {
  if (!periodoLimite && item.json.crg_periodo) {
    periodoLimite = item.json.crg_periodo;
  }
});

function getMesIndex(periodo) {
  if (!periodo) return 11;
  const mesNum = parseInt(periodo.toString().slice(-2));
  return mesNum - 1;
}

const mesLimiteIndex = getMesIndex(periodoLimite);

const linhasPorSeq = {};
items.forEach(item => {
  linhasPorSeq[item.json.dre_linha_seq] = {
    ...item.json,
    valoresCalculados: null
  };
});

Object.values(linhasPorSeq).forEach(linha => {
  if (linha.tipo_linha !== 'CONTA' && linha.tipo_linha !== 'CONSTANTE') return;

  const valores = {};
  let somaAcumulado = 0;

  if (linha.tipo_linha === 'CONSTANTE') {
    const valorConstante = parseFloat(linha.dre_linha_valor || 0);
    meses.forEach((mes, index) => {
      if (index <= mesLimiteIndex) {
        valores[mes] = valorConstante;
        somaAcumulado += valorConstante;
      } else {
        valores[mes] = 0;
      }
    });
  } else {
    meses.forEach((mes, index) => {
      if (index <= mesLimiteIndex) {
        const valor = linha[mes] || 0;
        valores[mes] = valor;
        somaAcumulado += valor;
      } else {
        valores[mes] = 0;
      }
    });
  }

  valores.conta_acumulado = somaAcumulado;

  linhasPorSeq[linha.dre_linha_seq] = {
    ...linha,
    ...valores,
    valoresCalculados: valores
  };
});

const todasLinhas = Object.values(linhasPorSeq);
todasLinhas.sort((a, b) => a.dre_linha_seq - b.dre_linha_seq);

return todasLinhas.map(linha => ({ json: linha }));

// ===== NODE 3: ACUMULADOS (ACUM VLR ANT) =====
const items = $input.all();
const meses = [
  'conta_janeiro', 'conta_fevereiro', 'conta_marco', 'conta_abril',
  'conta_maio', 'conta_junho', 'conta_julho', 'conta_agosto',
  'conta_setembro', 'conta_outubro', 'conta_novembro', 'conta_dezembro'
];

let periodoLimite = null;
items.forEach(item => {
  if (!periodoLimite && item.json.crg_periodo) {
    periodoLimite = item.json.crg_periodo;
  }
});

function getMesIndex(periodo) {
  if (!periodo) return 11;
  const mesNum = parseInt(periodo.toString().slice(-2));
  return mesNum - 1;
}

const mesLimiteIndex = getMesIndex(periodoLimite);

const linhasPorSeq = {};
items.forEach(item => {
  linhasPorSeq[item.json.dre_linha_seq] = { ...item.json };
});

function getValorLinha(numLinha, mes) {
  const linha = linhasPorSeq[numLinha];
  if (!linha) return 0;
  if (linha.valoresCalculados && linha.valoresCalculados[mes] !== undefined) {
    return linha.valoresCalculados[mes] || 0;
  }
  const valor = linha[mes];
  return valor !== null && valor !== undefined ? valor : 0;
}

function calcularAcumuladoValorAnterior(refLinha, mesLimiteIndex) {
  const match = refLinha.match(/#L(\d+)/);
  if (!match) return null;

  const numLinhaRef = parseInt(match[1]);
  const linhaReferenciada = linhasPorSeq[numLinhaRef];
  if (!linhaReferenciada) return null;

  const valores = {};
  let acumulado = 0;

  meses.forEach((mes, index) => {
    if (index <= mesLimiteIndex) {
      const valorMes = getValorLinha(numLinhaRef, mes);
      acumulado += valorMes;
      valores[mes] = acumulado;
    } else {
      valores[mes] = 0;
    }
  });

  valores.conta_acumulado = valores[meses[mesLimiteIndex]];
  return valores;
}

Object.values(linhasPorSeq).forEach(linha => {
  if (linha.tipo_linha !== 'ACUM VLR ANT') return;

  const referencia = linha.dre_linha_valor;
  if (!referencia) return;

  const valores = calcularAcumuladoValorAnterior(referencia, mesLimiteIndex);

  if (valores) {
    linhasPorSeq[linha.dre_linha_seq] = {
      ...linha,
      ...valores,
      valoresCalculados: valores,
      referencia_original: referencia
    };
  }
});

const todasLinhas = Object.values(linhasPorSeq);
todasLinhas.sort((a, b) => a.dre_linha_seq - b.dre_linha_seq);

return todasLinhas.map(linha => ({ json: linha }));

// ===== NODE 4: PERCENTUAIS =====
const items = $input.all();

const linhasPorSeq = {};
items.forEach(item => {
  linhasPorSeq[item.json.dre_linha_seq] = { ...item.json };
});

Object.values(linhasPorSeq).forEach(linha => {
  const percRef = linha.perc_ref;

  if (!percRef || percRef === '') {
    linha.conta_perc = null;
    return;
  }

  if (percRef === '#L%') {
    linha.conta_perc = 1;
    return;
  }

  if (percRef === '#L%%') {
    linha.conta_perc = null;
    return;
  }

  const match = percRef.match(/#L(\d+)/);
  if (match) {
    const numLinhaRef = parseInt(match[1]);
    const linhaReferenciada = linhasPorSeq[numLinhaRef];

    if (!linhaReferenciada) {
      linha.conta_perc = null;
      return;
    }

    const valorAtual = linha.conta_acumulado || 0;
    const valorReferencia = linhaReferenciada.conta_acumulado || 0;

    linha.conta_perc = valorReferencia === 0 ? 0 : valorAtual / valorReferencia;
    return;
  }

  linha.conta_perc = null;
});

const todasLinhas = Object.values(linhasPorSeq);
todasLinhas.sort((a, b) => a.dre_linha_seq - b.dre_linha_seq);

return todasLinhas.map(linha => ({ json: linha }));

// ===== NODE 2: FÓRMULAS =====
const items = $input.all();
const meses = [
  'conta_janeiro', 'conta_fevereiro', 'conta_marco', 'conta_abril',
  'conta_maio', 'conta_junho', 'conta_julho', 'conta_agosto',
  'conta_setembro', 'conta_outubro', 'conta_novembro', 'conta_dezembro'
];

let periodoLimite = null;
items.forEach(item => {
  if (!periodoLimite && item.json.crg_periodo) {
    periodoLimite = item.json.crg_periodo;
  }
});

function getMesIndex(periodo) {
  if (!periodo) return 11;
  const mesNum = parseInt(periodo.toString().slice(-2));
  return mesNum - 1;
}

const mesLimiteIndex = getMesIndex(periodoLimite);

const linhasPorSeq = {};
items.forEach(item => {
  linhasPorSeq[item.json.dre_linha_seq] = { ...item.json };
});

function corrigirFormula(formula) {
  if (!formula || typeof formula !== 'string') return formula;
  return formula.replace(/L#(\d+)/g, '#L$1').trim();
}

function expandirSomaLinha(formula) {
  const regex = /SOMA_LINHA\(#L(\d+):#L(\d+)\)/g;
  return formula.replace(regex, (match, inicio, fim) => {
    const linhas = [];
    for (let i = parseInt(inicio); i <= parseInt(fim); i++) {
      linhas.push(`#L${i}`);
    }
    return linhas.join('+');
  });
}

function expandirPerc(formula) {
  const regex = /PERC\(([^)]+)\)/g;
  return formula.replace(regex, (match, expressao) => `((${expressao})*100)`);
}

function getValorLinha(numLinha, mes) {
  const linha = linhasPorSeq[numLinha];
  if (!linha) return 0;
  if (linha.valoresCalculados && linha.valoresCalculados[mes] !== undefined) {
    return linha.valoresCalculados[mes] || 0;
  }
  const valor = linha[mes];
  return valor !== null && valor !== undefined ? valor : 0;
}

function calcularFormula(formula, mes) {
  let expressao = formula.replace(/#L(\d+)/g, (match, numLinha) => {
    return getValorLinha(parseInt(numLinha), mes);
  });
  try {
    const resultado = eval(expressao);
    return isFinite(resultado) ? resultado : 0;
  } catch (error) {
    return 0;
  }
}

Object.values(linhasPorSeq).forEach(linha => {
  if (linha.tipo_linha !== 'FORMULA') return;

  let formula = linha.dre_linha_valor;

  if (!formula ||
      formula.includes('APONTA PARA CONTA') ||
      formula.includes('QUE NAO TEM') ||
      formula.includes('PLANO DE CONTAS')) {
    return;
  }

  formula = corrigirFormula(formula);

  const isConstante = /^-?\d+(\.\d+)?$/.test(formula);

  if (isConstante) {
    const valorConstante = parseFloat(formula);
    const valores = {};
    meses.forEach((mes, index) => {
      valores[mes] = index <= mesLimiteIndex ? valorConstante : 0;
    });
    valores.conta_acumulado = valorConstante;
    linhasPorSeq[linha.dre_linha_seq] = {
      ...linha,
      ...valores,
      valoresCalculados: valores,
      formula_original: linha.dre_linha_valor,
      formula_processada: formula
    };
    return;
  }

  formula = expandirSomaLinha(formula);
  formula = expandirPerc(formula);

  const valores = {};
  let somaAcumulado = 0;

  meses.forEach((mes, index) => {
    if (index <= mesLimiteIndex) {
      const valor = calcularFormula(formula, mes);
      valores[mes] = valor;
      somaAcumulado += valor;
    } else {
      valores[mes] = 0;
    }
  });

  valores.conta_acumulado = somaAcumulado;

  linhasPorSeq[linha.dre_linha_seq] = {
    ...linha,
    ...valores,
    valoresCalculados: valores,
    formula_original: linha.dre_linha_valor,
    formula_processada: formula
  };
});

const todasLinhas = Object.values(linhasPorSeq);
todasLinhas.sort((a, b) => a.dre_linha_seq - b.dre_linha_seq);

return todasLinhas.map(linha => ({ json: linha }));

