// ===== MÚLTIPLOS PASSES =====
// Cada passagem recalcula todas as fórmulas usando os valores
// já disponíveis em valoresCalculados. Referências para frente
// (seq maior) ficam corretas a partir da 2ª passagem.
const MAX_PASSES = 3;

for (let pass = 0; pass < MAX_PASSES; pass++) {
  Object.values(linhasPorSeq).forEach(linha => {
    if (linha.tipo_linha !== 'FORMULA') return;

    const resultado = processarFormula(linha);
    if (!resultado) return;

    linhasPorSeq[linha.dre_linha_seq] = {
      ...linha,
      ...resultado.valores,
      valoresCalculados: resultado.valores,
      formula_original: resultado.formula_original,
      formula_processada: resultado.formula_processada
    };
  });
